            matcher: {
              id: FieldMatcherID.byNames,
              options: {
                mode: ByNamesMatcherMode.include,
                names: ['field1', 'field2'],
              },
            },
            properties: [{ id: 'custom.footer.reducers', value: ['sum'] }],
          },
        ])
